public int minDeletions(String s) {
    int[] freq = new int[26];
    HashSet<Integer> used = new HashSet<>();
    int deletions = 0;

    for (char c : s.toCharArray()) {
        freq[c - 'a']++;
    }

    for (int count : freq) {
        while (used.contains(count) && count > 0) {
            deletions++;
            count--;
        }
        used.add(count);
    }

    return deletions;
}
```

